PSA_ORIGINAL = {
  "2": {
    "7": "<p><strong>YHWH amar elai beni atta ani hayom yelidticha</strong> (<em>Yhwh ʾāmar ʾēlay, bĕnî ʾattâ ʾănî hayyôm yĕlídtîkā</em>): 'The LORD said to me: You are my Son; today I have begotten you.' The royal adoption formula of Ps 2:7 was applied to the Davidic king at his enthronement — the king became YHWH's 'son' in a representative capacity (2 Sam 7:14; Ps 89:26-27). The NT applies it to Jesus at three Christological moments: the baptism (Matt 3:17), the transfiguration (2 Pet 1:17), and the resurrection (Acts 13:33; Heb 1:5; 5:5). The resurrection is the decisive 'today' in NT usage: the day of Christ's enthronement at the Father's right hand is the day of divine sonship's full eschatological declaration.</p>"
  },
  "8": {
    "4": "<p><strong>mah enosh ki tizkerenu uben adam ki tipqedenu</strong> (<em>mâ-ʾĕnôš kî-tizqĕrennû ûben-ʾādām kî tipqĕdennû</em>): 'What is man that you are mindful of him, and the son of man that you care for him?' <em>Ben adam</em> (son of man) in Ps 8 is the representative human made lower than the heavenly beings and crowned with glory — a meditation on Gen 1:26-28's dominion mandate. The NT (Heb 2:5-9) applies Ps 8 to Christ as the true human who fulfills the Adamic mandate: 'We do not yet see everything in subjection to him, but we see him who for a little while was made lower than the angels, namely Jesus, crowned with glory and honor because of the suffering of death.' Christ recapitulates and fulfills humanity's Ps 8 vocation.</p>"
  },
  "22": {
    "1": "<p><strong>eli eli lamah azavtani</strong> (<em>ʾēlî ʾēlî lāmāh ʿăzabtānî</em>): 'My God, my God, why have you forsaken me?' The opening of the Passion Psalm in its Hebrew form. The Aramaic at the cross (Mark 15:34: <em>Eloi eloi lema sabachthani</em>) uses the Aramaic form of the Psalm's Hebrew opening, suggesting Jesus was quoting from memory in the vernacular. The Psalm moves from dereliction (vv. 1-21) to proclamation and praise (vv. 22-31) — ending not in abandonment but in universal witness ('all the ends of the earth shall turn to the LORD', v. 27). The early church understood Jesus's citation of the Psalm's opening as invoking the whole Psalm, including its vindication ending.</p>"
  },
  "110": {
    "1": "<p><strong>neum YHWH laadoni shev limini ad ashit oyvecha hadom leraglecha</strong> (<em>nĕʾum Yhwh laʾdōnî, šēb liymînî ʿad-ʾāšît ʾōyĕbêkā hădōm lĕraglêkā</em>): 'The oracle of YHWH to my lord: Sit at my right hand until I make your enemies your footstool.' <em>Neum</em> (oracle of) is the formula for divine speech — the highest possible speech-authority marker in Hebrew prophecy. David writes <em>laadoni</em> (to my lord), creating the theological puzzle Jesus exploits in Matt 22:41-46: how can David's descendant also be David's lord? The Davidic Messiah must be more than a Davidic son; only divine sonship accounts for the double identity. <em>Shev limini</em> (sit at my right hand): enthronement at the supreme position of divine authority — the NT applies this to the resurrection/ascension as Christ's enthronement (Acts 2:34-35; Eph 1:20-21; Heb 1:3).</p>",

    "4": "<p><strong>nishba YHWH velo yinachem atta kohen leolam al divrati malkitsedek</strong> (<em>nišbaʿ Yhwh wĕlōʾ yinnāḥēm ʾattā-kōhēn lĕʿôlām ʿal-diḇrātî malkîṣedeq</em>): 'YHWH has sworn and will not change his mind: You are a priest forever after the manner of Melchizedek.' The divine oath (<em>nishba ... velo yinachem</em>) makes this the most certain OT promise after the Abrahamic oath. <em>Malkitsedek</em> (Melchizedek, king of righteousness): the mysterious priest-king of Gen 14:18-20 who blessed Abraham and received a tithe — without genealogy, without recorded birth or death. Hebrews 7 uses the silence of Scripture about Melchizedek's origins as a typological argument: a priesthood with no recorded beginning or end points to an eternal priesthood.</p>"
  }
}

PSA_CONTEXT = {
  "1": {
    "1": "<p>The Psalter (150 poems spanning roughly David\'s reign to the post-exilic period) was the hymnbook of the Second Temple — used in liturgy from the restoration (Ezra-Nehemiah) through the NT period. The Dead Sea Scrolls (1QPs, 4QPsa-r, and 11QPsa) preserve the most psalms of any biblical book among the Qumran community, indicating the Psalter\'s centrality in Jewish worship. The Psalter is organized into five books (Ps 1-41, 42-72, 73-89, 90-106, 107-150) mirroring the five books of Moses, each ending with a doxology. The arrangement suggests a canonical editorial design: the Psalter tells the story of Israel\'s covenant relationship with YHWH from Torah-delight (Ps 1) to universal praise (Ps 150).</p>"
  },
  "90": {
    "1": "<p><b>A Prayer of Moses the man of God</b> — the only psalm attributed to Moses in the entire Psalter. The attribution is debated by critical scholars but the heading is early; the psalm was received as Mosaic in the Second Temple period. It opens Book IV (Ps 90-106), the collection that functions as a theological response to the crisis of the Davidic monarchy\'s collapse and the Babylonian exile. Book IV provides an answer to the lament of Ps 89: even when the Davidic covenant seems to have failed, <i>YHWH</i> has been Israel\'s <i>maon</i> (dwelling place, home, refuge) across all generations. The psalm\'s setting is therefore Israel after the exile, reading a Mosaic prayer that relocates identity from land and temple to YHWH himself.</p>",
    "2": "<p><b>Before the mountains were born</b> — the cosmos-founding language that precedes the existence of the most enduring features of the known world. Mountains in the ancient Near East were the oldest things imaginable: the pillars of the sky, the dwelling places of gods, older than human memory. YHWH predates them all. The phrase <i>me\'olam ad olam</i> (from age to age / from everlasting to everlasting) brackets the divine existence at both ends of time — no beginning accessible to human thought, no end conceivable. This is the psalm\'s theological premise: the eternal God is the only stable home for creatures whose own existence is radically impermanent.</p>",
    "3": "<p><b>You turn human beings back to dust</b> — the reversal of the creation act of Gen 2:7 (YHWH formed Adam from the dust of the ground) and the covenant curse of Gen 3:19 (\"dust you are and to dust you will return\"). The divine command \"Return, O children of Adam\" (<i>benei adam</i>) echoes both the creation narrative and the judgment. The psalm places human transience within the divine governance: mortality is not a biological accident but an expression of YHWH\'s sovereign ordering of human life. The repeated address to \"children of Adam\" (generic humanity, not specifically Israel) gives the psalm a universal anthropological scope.</p>",
    "4": "<p><b>A thousand years in your sight are like yesterday after it has passed</b> — the divine perspective on time: a millennium is experientially equivalent to the receding past of a single day or a night watch (approximately three hours). This is not a statement about the unreality of time but about the difference between creaturely and divine modes of experiencing it. The comparison \"like yesterday after it has passed\" (<i>ke\'etmol ki ya\'avor</i>) specifies a yesterday that is already past — not vivid yesterday but the fading, already-receding yesterday. Peter applies this specifically to the delay of the parousia (2 Pet 3:8), using it to counter impatient demands for immediate eschatological action.</p>",
    "5": "<p><b>You sweep them away like a sudden flood</b> — the first of several images for the brevity and vulnerability of human life. The flood-metaphor implies overwhelming force and complete loss of control: humans are swept away by YHWH\'s action, not by mere biological process. The dream-imagery that follows points to the evanescent quality of life: a dream is vivid during experience but disappears completely upon waking. The grass metaphor begins here and is developed through v6. This cluster of images — flood, dream, grass — is a recognized literary topos in ANE wisdom literature (compare Job 14:1-2) for the fragility of human existence.</p>",
    "6": "<p><b>In the morning it blossoms and shoots up; by evening it is mown down and dry</b> — the grass metaphor spans a single day as the compressed image of a complete human life: birth-to-death within the span of morning-to-evening. This is the same image that Isaiah 40:6-8 uses for the contrast between human transience and YHWH\'s eternal word: \"All people are like grass... the grass withers and the flowers fall, but the word of our God stands forever.\" The Psalter and the prophets draw on the same wisdom image to locate human brevity within divine permanence. The psalm will later (v12) turn this observation from despair into practical wisdom.</p>",
    "7": "<p><b>We are brought to an end by your anger</b> — the crucial shift: this psalm is not merely philosophical reflection on mortality but a covenantal lament. The human brevity described in vv 5-6 is specifically framed as the effect of divine anger (<i>aph</i>) and fury (<i>hemah</i>). The \"we\" is the covenant community. The psalm does not say that human transience is simply the result of finitude; it says it is the context within which YHWH\'s anger operates. This locates the psalm within the covenant-lawsuit tradition: Israel under the consequences of unfaithfulness, experiencing the divine displeasure that the Torah described as the covenant curse (Deut 28:15-68).</p>",
    "8": "<p><b>You have placed our sins before you and our hidden faults in the full light of your presence</b> — the divine omniscience as it bears on judgment. \"Hidden faults\" (<i>alumenu</i>) — those wrongs the community has kept from public view, the sins concealed from other humans but not from YHWH. The same principle that Ps 64:5 condemns in the wicked (\"who will see us?\") is here confessed about the community itself: the assumption of hiddenness is false. The \"full light of your presence\" (<i>lim\'or panekha</i>) — the face-light of divine presence — serves as the ultimate revealer. No concealment survives the divine gaze.</p>",
    "9": "<p><b>All our days slip away under your wrath</b> — the entire lifespan framed by divine displeasure. \"We bring our years to an end like a breath\" — the Hebrew word is <i>hegeh</i>, which can mean a sigh, a groan, or the low murmur of meditation. The years pass with the sound of a sigh: not even a cry, just an exhaled breath. The image is of a life that does not end with fanfare but simply dissipates. This verse has moved from the anger of vv 7-8 to the ordinary passage of time: even lives not marked by dramatic judgment simply sigh away. The wrath is not periodic punishment but the ambient condition of creaturely existence under divine assessment.</p>",
    "10": "<p><b>The span of our years is seventy — or if we are strong, eighty</b> — not a biological claim but a wisdom observation. In the ancient world, many died far younger (infant mortality was extremely high); the psalm treats seventy and eighty as the upper range of normal life expectancy. Notably, Moses himself lived 120 years (Deut 34:7) and is recorded as vigorous to the end — the psalm\'s putative author was an exception to the rule he describes, which is part of its dramatic force. \"Only toil and grief\" (<i>amal va\'aven</i>) — even the strong years at 80 contain only labor and trouble. The psalm does not romanticize longevity: more years means more accumulated suffering.</p>",
    "11": "<p><b>Who truly grasps the force of your anger?</b> — a rhetorical question that implies the answer is \"almost no one.\" The \"force\" (<i>oz</i>) of divine anger is not grasped by ordinary human perception; only the one who fears YHWH as the divine wrath deserves to be feared is able to perceive it accurately. This is a wisdom observation: the failure to fear YHWH properly is itself evidence of a distorted perception of reality. The fear of YHWH (<i>yirah</i>) that properly calibrates the response to divine anger is the beginning of wisdom (Prov 1:7; 9:10) — and its absence is evidence of the fool\'s miscalibrated worldview.</p>",
    "12": "<p><b>Teach us, then, to count our days aright</b> — the pivot from lament to petition. The observation of human transience (vv 3-11) now generates a specific request: teach us to <i>number</i> our days, to count them one by one with the awareness that each is finite and irreplaceable. \"That we may acquire a wise heart\" (<i>levav chokmah</i>) — wisdom is not the natural result of aging but the outcome of deliberate attention to mortality. The wisdom tradition (Prov 9:10; Eccl 12:1-7) consistently treats the awareness of death as the catalyst for wisdom rather than as an occasion for either denial or despair. This is the psalm\'s practical anthropology.</p>",
    "13": "<p><b>Turn back, LORD! How long will this go on?</b> — <i>shuvah</i> addressed to YHWH: the standard covenant lament formula asking God to turn back to his people (Ps 6:4; 80:14; Lam 5:21). The \"how long\" (<i>ad matai</i>) is the temporal cry of the lament psalms — the open-ended question that expresses the felt endlessness of the current distress without denying the expectation that it will end. \"Have mercy on your servants\" — the community identifies as YHWH\'s <i>avadim</i> (servants), the covenant relational term that the prayer returns to at vv 16 and 17. The appeal is to covenant relationship, not to human merit.</p>",
    "14": "<p><b>Fill us in the morning with your steadfast love</b> — <i>hesed</i> in the morning: the same pattern as Ps 92:2 (declaring steadfast love each morning) and Lam 3:22-23 (\"his mercies are new every morning\"). The \"morning\" is the time of rescue in the Psalter — the darkness of night is the time of distress and the morning is when YHWH acts (Ps 30:5; 46:5; 130:5-6). The prayer asks for <i>hesed</i>-saturation (<i>male</i>, fill us) at the beginning of each day so that the day\'s experience is shaped by covenant love rather than by the awareness of divine wrath from vv 7-11. The joy and celebration that follow are the natural fruits of hesed-saturation.</p>",
    "15": "<p><b>Give us gladness to match the days you have made us suffer</b> — the precise proportionality of the request: not merely some gladness but gladness (<i>simhah</i>) equivalent in measure to the years of affliction. This is the same logic as YHWH\'s response to Job: double restoration (Job 42:10). It is also the eschatological promise of Isaiah 61:7 (\"instead of their shame my people will receive a double portion... everlasting joy will be theirs\"). The prayer does not ask YHWH to minimize the past suffering but to match it with future joy — a redemptive transformation of the ledger, not an erasure. The \"years\" of trouble are still countable; the years of joy must count at least as many.</p>",
    "16": "<p><b>Let your work appear to your servants</b> — YHWH\'s <i>po\'al</i> (work/deed) made visible to the community. In the context of exile, this prayer asks for visible signs of divine action in history — the kind of demonstrable intervention that the Exodus generation saw (the psalm\'s Mosaic attribution connects the community\'s prayer to the paradigm of visible divine action). \"Your splendor shine on their children\" — the next generation: the prayer spans beyond the present moment to the children of those now suffering. The continuity of divine favor across generations is the heart of covenant blessing (Deut 7:9; Ps 103:17-18).</p>",
    "17": "<p><b>May the favor of the LORD our God rest upon us</b> — <i>no\'am YHWH</i> (the pleasantness/beauty/favor of YHWH) as the crowning request. This is the rare word used in Ps 27:4 for the single thing David desires: \"to gaze on the beauty of the LORD.\" The favor of divine presence is the answer to the psalm\'s opening claim: YHWH is our dwelling (v1) and our request is that his favor may \"rest upon us\" (<i>alenu</i>). \"Establish the work of our hands\" — the double repetition (\"establish... yes, establish\") is emphatic and liturgical. Human labor becomes meaningful only when it is taken up and made permanent by the divine act of establishment. The psalm ends not in resignation but in confident petition.</p>"
  },
  "91": {
    "1": "<p><b>Whoever lives in the shelter of the Most High will rest in the shadow of the Almighty</b> — the first two verses of this psalm deploy four divine names/titles in rapid succession: <i>Elyon</i> (Most High), <i>Shaddai</i> (Almighty), <i>YHWH</i>, and <i>Elohim</i> — an unusual concentration that signals the comprehensive divine protection being promised. The \"shelter\" (<i>seter</i>) of God Most High evokes the Tabernacle and Temple as the physical locus of divine protection — the innermost parts of the sanctuary where YHWH\'s presence dwelt. \"Shadow of the Almighty\" (<i>tzel Shaddai</i>) uses the same shadow/wings imagery as Ps 63:7 and anticipates v4\'s explicit wings metaphor. The psalm addresses the individual in crisis rather than the community.</p>",
    "2": "<p><b>I will say to the LORD, \'You are my refuge and my fortress, my God, in whom I trust\'</b> — the shift from third person (v1) to first person marks the transition from general claim to personal confession. The paired military metaphors (refuge / fortress) are the standard protective architecture vocabulary of the Psalter (Ps 18:2; 31:2-3; 62:2-7). The affirmation \"in whom I trust\" (<i>evtach bo</i>) is the relational formula of covenant confidence — the surrender of self-reliance for dependence on YHWH. The two-verse introduction (vv 1-2) provides the theological premise from which the specific promises of vv 3-13 follow: YHWH\'s protective identity is the ground for the detailed assurances that follow.</p>",
    "3": "<p><b>He will rescue you from the hunter\'s trap and from every deadly disease</b> — two representative categories of danger that frame the psalm\'s scope. The \"hunter\'s trap\" (<i>pah yakush</i>) — the ambush, the snare, the concealed threat that the prey does not see coming — is the social and military danger. The \"deadly disease\" (<i>dever hawot</i>) — the plague, the epidemic — is the natural danger. Both represent the extremes of human vulnerability: the deliberate malice of enemies and the impersonal force of disease. The psalm will expand these two categories into a four-part scheme in vv 5-6, covering all four combinations of human/natural × night/day.</p>",
    "4": "<p><b>He will shelter you under his feathers; you will find refuge beneath his wings</b> — the wings imagery has the same dual reference as Ps 63:7: (1) the cherubim of the Ark of the Covenant, whose outstretched wings formed YHWH\'s throne (Exod 25:20; 1 Kgs 8:6-7); and (2) the mother-bird of Deut 32:11 (\"like an eagle that stirs up its nest and hovers over its young, spreading its wings to catch them\"). Both images communicate protective presence: the liturgical sheltering of the sanctuary and the maternal instinct of the divine guardian. \"His faithfulness is your shield and armor\" — <i>emet</i> (faithfulness, truth) as the practical defensive equipment.</p>",
    "5": "<p><b>You will not fear the terror that comes in the night or the arrow that flies in the daylight</b> — the first pair in the four-part danger scheme: night terror (dread, psychological attack) and daytime arrow (physical assault). In ancient warfare, night raids were particularly terrifying because darkness removed the possibility of seeing the threat approaching. The daytime arrow is the visible military attack in the open. The pair covers all times of day and both psychological and physical categories of threat. The promise is not immunity from danger but the removal of fear before it: the one who dwells in divine protection is freed from the <i>terror</i> even when the danger is present.</p>",
    "6": "<p><b>Nor the disease that moves through the dark or the plague that strikes at noon</b> — the second pair: the disease that \"walks in darkness\" and the plague that \"strikes at noon.\" The personification of disease as a walking predator reflects ancient understandings of epidemic illness as a quasi-personal agent (Hab 3:5 also personifies <i>dever</i> as a companion of YHWH\'s advance). The \"noon\" plague (<i>yashud tzahorayim</i>) may refer to heatstroke or to a demon associated with midday — the Septuagint translated it as \"the noonday demon\" (<i>daimonion mesembrinon</i>), which became an influential image in Christian monastic theology for the spiritual acedia that attacks at midday.</p>",
    "7": "<p><b>A thousand may fall beside you, ten thousand at your right hand — but it will not reach you</b> — the military formation idiom: the numbers 1,000 and 10,000 appear together as the two standard military units in ancient Israelite accounts (1 Sam 18:7; 29:5 — \"Saul has slain his thousands, and David his tens of thousands\"; Mic 6:7 — \"ten thousands of rivers of oil\"). The right hand was the sword hand, the position of greatest danger in battle formation. The promise is that the protected one stands unharmed at the center of massive destruction — a covenantal promise of divine selection within judgment (as in the Exodus plagues where Israel was protected while Egypt suffered).</p>",
    "8": "<p><b>You will only watch with your own eyes and see the fate of the wicked</b> — the protected one will be a witness rather than a victim. \"The fate of the wicked\" (<i>shillumat resha\'im</i>) — the retribution/payment that comes upon the wicked — is observed from a position of safety. This is the divine justice structure of the lament psalms: the same reversal pattern where the innocent are vindicated while the wicked face the consequences their own actions generate (Ps 37:34; 52:5-6; 91:8). The witness-role of the protected person also has a communal function: their survival testifies to the reality of divine protection for the rest of the community.</p>",
    "9": "<p><b>Because you have made the LORD your refuge, the Most High your dwelling place</b> — the conditional structure of the promise. The protection described in vv 3-8 is contingent on this foundational choice: making YHWH (not military alliance, not wealth, not human protection) the actual refuge. The word <i>machsekha</i> (your refuge) echoes <i>mano</i> from v1 and <i>machaseh</i> from v2 — the entire psalm is organized around the vocabulary of refuge and shelter. This verse is the theological hinge of the psalm: the protection is not automatic or universal but specifically available to those who have made YHWH their actual dwelling-place-of-trust.</p>",
    "10": "<p><b>No evil will happen to you, and no plague will come close to your home</b> — the comprehensive promise of covenantal protection. \"Your home\" (<i>ohalekha</i>) — tent/dwelling — connects the individual\'s protection to the family unit. The same pattern appears in the Passover narrative: the protection extends to the household marked by the blood (Exod 12:7, 13). In the Deuteronomic blessing-and-curse framework, the protection of home and family from plague and disaster is one of the specific covenant blessings (Deut 28:3-6). The psalm is applying the covenant blessing promises to the individual who has made YHWH his refuge.</p>",
    "11": "<p><b>He will command his angels to guard you in all your ways</b> — the divine delegation of protection to angelic agents. This is one of the most explicit angelic guardian promises in the OT, and it became one of the most theologically active verses in Second Temple Judaism and the NT. Satan quotes this verse (and v12) in the wilderness temptation of Jesus (Matt 4:6; Luke 4:10-11), attempting to apply a covenant protection promise as a license to test YHWH — which Jesus refuses as a violation of Deut 6:16 (\"do not test YHWH your God\"). The temptation misapplies the promise by treating it as a basis for deliberate self-endangerment rather than a source of confidence in genuine danger.</p>",
    "12": "<p><b>They will hold you up in their arms so your foot does not strike against a stone</b> — the specific physical content of the angelic mission: bearing up (the physical lifting/carrying gesture) so that the foot — the point of contact with uneven terrain, the source of stumbling — does not strike against a stone. The image is of a guardian walking alongside who prevents accidental injury. Satan\'s quotation of this verse in the temptation narrative transforms it from a promise of protection in ordinary danger into a claimed guarantee of protection from self-inflicted danger — precisely the distortion Jesus refuses. The psalm\'s promise is for those walking <i>in their ways</i> (v11), not for those testing YHWH.</p>",
    "13": "<p><b>You will walk on the lion and the cobra; you will trample the young lion and the serpent underfoot</b> — the four animals represent the representative dangers of the ancient Palestinian landscape: <i>shachal</i> (lion, the great predator), <i>peten</i> (cobra, the deadly serpent), <i>kephir</i> (young lion, in full predatory strength), and <i>tannin</i> (serpent/dragon, including the mythological chaos-creature). The trampling of serpents under foot has a resonance that runs from Gen 3:15 (the seed of the woman crushing the serpent\'s head) through Luke 10:19 (Jesus giving the disciples authority to trample snakes and scorpions) to Rev 20:2 (the dragon bound). The accumulated canonical weight of serpent-treading language gives this verse an eschatological register.</p>",
    "14": "<p><b>\'Because he clings to me in love,\' declares the LORD</b> — the direct divine speech begins here and continues through v16, which is rare in the Psalter. The covenant-attachment verb <i>hashaq</i> (to cling to in love, to be set upon) is a term of deep attachment — it is used of Isaac\'s binding in Gen 22 and of the covenant love of Deut 7:7 (\"YHWH did not set his love [<i>hashaq</i>] on you because you were more numerous\"). \"I will set him beyond reach\" (<i>asagvehu</i>) — placed on an inaccessible height, the fortress-height imagery. \"Because he truly knows who I am\" (<i>yada shemi</i>) — the knowledge of the Name as covenant intimacy, not mere information.</p>",
    "15": "<p><b>\'When he calls on me I will answer\'</b> — the four divine commitments in vv 14-15 form a chiastic structure: rescue / set beyond reach (v14) // answer / be with in trouble / rescue / honor (v15). The divine promise to answer prayer is the covenant guarantee of Ps 50:15 (\"call on me in the day of trouble; I will deliver you, and you will honor me\"). \"I will be with him in his trouble\" (<i>immo anochi betzarah</i>) — divine presence as the content of the promise: not exemption from trouble but the presence of YHWH within the trouble. \"Give him honor\" (<i>akabbedehu</i>) — public vindication, the restoration of social dignity that trouble had stripped away.</p>",
    "16": "<p><b>\'I will give him a full life and let him see my saving power\'</b> — the closing divine promise: length of days (<i>orech yamim</i>) and the vision of salvation (<i>yeshu\'ati</i>). \"Full life\" is literally \"length of days\" — a complete, satisfied human lifespan (compare Ps 21:4; Prov 3:2, 16). \"Let him see my saving power\" — the same vision as Moses\' experience at the sea crossing: seeing with physical eyes the mighty act of divine rescue. This is both a personal promise and an echo of the Moses-attribution of Ps 90: the one who prays Moses\' prayer of longing (Ps 90:16 — \"let your work appear to your servants\") receives this divine answer: you will indeed see YHWH\'s salvation.</p>"
  },
  "92": {
    "1": "<p><b>A Psalm. A Song for the Sabbath day</b> — the only psalm in the Psalter with a Sabbath designation. In the Second Temple period it became the Levitical song for Sabbath morning worship in the Temple; this practice is attested in the Mishnah (Tamid 7:4) and continued in synagogue liturgy. The Sabbath context frames the entire psalm: the thanksgiving it opens with is specifically the act of rest-and-recognition that characterizes the seventh day. \"It is good\" (<i>tov</i>) to give thanks — the creation word from Gen 1 applied to worship. Just as each day of creation was declared \"good,\" so the Sabbath act of giving thanks to YHWH is declared good. The Sabbath is the day for recognizing what YHWH has made.</p>",
    "2": "<p><b>To declare your steadfast love each morning and your faithfulness through every night</b> — the morning/evening structure for worship mirrors the daily <i>tamid</i> (continual) offerings in the Temple: a lamb offered at dawn and at dusk (Exod 29:38-42). The twin realities being proclaimed — <i>hesed</i> (steadfast love, covenant loyalty) in the morning and <i>emunah</i> (faithfulness, trustworthiness) through the night — are the two covenant attributes of YHWH that structure all of human experience. Morning is the time of rescue (Ps 30:5; 90:14); night is the time of testing and waiting. Hesed and emunah are the appropriate response to each: confidence in the morning, trust through the darkness.</p>",
    "3": "<p><b>To the music of the ten-stringed lute and the melody of the harp, with the rippling of the lyre</b> — three specific instruments: the <i>asor</i> (ten-stringed instrument, possibly a psaltery), the <i>navel</i> (harp or lyre), and the <i>kinnor</i> (the classic Israelite lyre, the instrument associated with David). The association of praise with instrumental music is deeply embedded in temple worship: David organized the Levitical musicians (1 Chr 6:31-47; 15:16-24; 25:1-8) and the instruments are listed multiple times in the Psalter\'s headings. \"With the rippling of the lyre\" (<i>bigayon bekinnor</i>) — the rippling or murmuring of the instrument\'s sound, suggesting a sustained, vibrating resonance.</p>",
    "4": "<p><b>You have made me glad, LORD, by what you have done</b> — the personal testimony of joy generated by divine works. \"What your hands have made\" (<i>po\'alekha</i>) — the works of YHWH\'s activity in creation and history that the worshiper has personally observed and experienced. The Sabbath context is significant: the seventh day was set aside specifically for contemplating and celebrating what YHWH had made and done (Gen 2:2-3; Exod 20:11). The Sabbath is the day for converting observation of divine work into personal joy. The psalm thus embodies its own Sabbath theology: it is itself the act of singing for joy over YHWH\'s works that the Sabbath calls for.</p>",
    "5": "<p><b>How great are your works, LORD! How utterly deep are your thoughts!</b> — the exclamation of wonder before the unfathomable divine <i>machshevot</i> (thoughts, plans, purposes). This is the wisdom tradition\'s awe before divine wisdom (Job 26:14; Isa 55:8-9; Rom 11:33-36: \"how unsearchable his judgments and his paths beyond tracing out!\"). The \"depth\" of divine thoughts contrasts with the shallowness of the \"senseless person\" in v6 who cannot grasp what YHWH is doing. The psalm sets up a fundamental epistemological contrast: those who can perceive divine depth vs. those who are too shallow to see it. This contrast drives the rest of the psalm.</p>",
    "6": "<p><b>A senseless person cannot grasp it, and a fool does not understand</b> — the wisdom vocabulary of Proverbs: <i>ba\'ar</i> (brutish, senseless — the person without spiritual perception, like an animal) and <i>kesil</i> (fool — the moral fool of the wisdom tradition, not unintelligent but morally miscalibrated). What they cannot understand is explained in v7: the temporary flourishing of the wicked. The failure to understand this specific phenomenon reveals a deeper failure of perception: the inability to grasp the temporal structure of divine governance. The wisdom tradition\'s response to the prosperity of the wicked is not resignation but perspective — the long view that sees the trajectory, not just the current moment.</p>",
    "7": "<p><b>The wicked may spring up like grass and every evildoer may flourish, but they are headed for eternal ruin</b> — the grass image from Ps 90:5-6 reappears, but now applied to the wicked specifically. The wicked\'s flourishing is temporary and follows the same organic trajectory as the grass: rapid growth followed by equally rapid death. \"Eternal ruin\" (<i>lehichadam ad olam</i>) — the permanent destruction that is the endpoint of the wicked\'s trajectory. The Sabbath psalm addresses the perennial wisdom question of why the wicked prosper by placing their flourishing within the correct timeframe: it is real but temporary; their end is the permanent opposite of the righteous\'s permanence (vv 12-15).</p>",
    "8": "<p><b>While you, LORD, are exalted on high forever</b> — the contrast with the temporary flourishing of the wicked. YHWH\'s <i>marom</i> (height, exaltation) is permanent and absolute. The enthronement theology of the Psalter (Ps 93, 96-99) is implicit here: YHWH\'s cosmic kingship is the stable backdrop against which all human fortunes — wicked flourishing and righteous suffering alike — are assessed. The permanence of divine exaltation is not a cold comfort but the guarantee of the ultimate structure of reality: YHWH\'s righteous governance is real, even when the present moment seems to contradict it.</p>",
    "9": "<p><b>Yes, your enemies, LORD — your enemies will certainly perish</b> — the emphasis marker (<i>ki hinne</i>, \"for behold\") followed by the double mention of \"your enemies\" creates a rhetorical intensification. The enemies of YHWH are those who oppose his moral order — specifically the evildoers of v7 who have flourished temporarily. \"All who do evil will be scattered\" (<i>yitparedu</i>) — dispersed, broken apart, losing the cohesion of their power. The military language of scattering (defeat in battle) is applied to YHWH\'s cosmic opposition to evil: the enemies are not merely punished but dissolved as a force.</p>",
    "10": "<p><b>But you have raised my strength high like the horn of a wild bull; you have anointed me with fresh oil</b> — the personal testimony of divine empowerment. The <i>re\'em</i> (wild bull or aurochs) was the most powerful animal in the ancient Canaanite landscape — its horns were a standard image of irresistible strength (Num 23:22; 24:8; Deut 33:17). The horn raised high signals exaltation and power received from YHWH. \"Anointed with fresh oil\" (<i>balothi beshemen ra\'anan</i>) — fresh, not rancid oil: the consecration oil that sets apart priests and kings (Exod 29:7; 1 Sam 10:1). The worshiper\'s experience of divine empowerment is described in royal/priestly terms.</p>",
    "11": "<p><b>My eyes have seen the downfall of my enemies; my ears have heard the ruin of those who rose against me</b> — personal testimony of witnessed vindication. The sensory specificity (eyes, ears) grounds the claim: this is not abstract hope but reported experience. The pattern — personal crisis, appeal to YHWH, divine vindication witnessed by the one rescued — is the standard <i>todah</i> (thanksgiving) narrative structure. The rescued person returns to the temple to report what they saw and heard (Ps 66:16: \"come and hear, all you who fear God; I will tell what he has done for me\"). This verse is the brief narrative moment of the psalm\'s thanksgiving structure.</p>",
    "12": "<p><b>The righteous person flourishes like the palm tree and grows tall like a cedar of Lebanon</b> — the two signature plants of long-lived productivity. The date palm (<i>tamar</i>) was prized in ancient Israel for its fruit (dates were a staple food), its wood, and its extreme longevity — a palm tree can live for over a century and continue bearing fruit. The cedar of Lebanon (<i>erez lalevanon</i>) was the most prestigious timber tree of the ancient Near East, associated with Solomon\'s Temple (1 Kgs 6:9-10, 15-20), with divine majesty (Ps 29:5), and with permanence. Both images contrast with the grass of v7 (the wicked\'s trajectory) — the righteous grow tall and last rather than springing up and dying in a day.</p>",
    "13": "<p><b>Planted in the house of the LORD, they will flourish in the courts of our God</b> — the temple as the location of the righteous person\'s flourishing. Being \"planted\" (<i>shethulim</i>) in YHWH\'s house is the specific condition of the psalm\'s promise: the flourishing is not a general natural process but is specifically linked to the sanctuary presence. This connects to Ps 1:3 (the one who meditates on Torah is \"like a tree planted by streams of water\") and to the Ezekiel 47 vision of the trees growing on both banks of the temple river. The righteous person flourishes because they are rooted in the source of divine life.</p>",
    "14": "<p><b>In old age they still produce fruit; they remain vigorous and full of life</b> — the counter-image to the 80-year lifespan of Ps 90:10 (which contains \"only toil and grief\"). Here old age is characterized by continued fruitfulness and full vitality (<i>deshenim vera\'ananim</i>, fat and fresh). The image of the bearing-in-old-age tree applies the biological observation that well-watered, established trees continue producing fruit late in life when younger, less-rooted plants have long since died. In the covenant framework, this is the longevity-blessing of faithful covenant life: not merely survival into old age but continued productive life (compare Sarah bearing Isaac, Abraham remaining vigorous, Moses\' eyesight unimpaired at 120).</p>",
    "15": "<p><b>Bearing witness that the LORD is just — he is my rock, and there is nothing wrong in him</b> — the theological function of the righteous person\'s long fruitful life: it is a testimony to YHWH\'s justice. The continued flourishing of the righteous person is itself a <i>lehagid</i> (a declaration, a proclamation) to the community that YHWH\'s governance is morally ordered. This answers the question implicit in vv 6-9: how do we know the wicked are really headed for ruin and the righteous for flourishing? The long-lived, fruit-bearing righteous person is the living answer. \"There is nothing wrong in him\" (<i>lo avlatah bo</i>) — no injustice, no crookedness, no moral deficiency in YHWH.</p>"
  },
  "93": {
    "1": "<p><b>The LORD reigns!</b> — the proclamation <i>YHWH malak</i> (or <i>YHWH malakh</i>) is the enthronement formula that identifies Psalms 93, 96, 97, 98, and 99 as the Enthronement Psalms. The formula has been understood either as a present tense declaration (\"YHWH is king\") or as a performative enthronement cry (\"YHWH has become king\"). Book IV of the Psalter (Ps 90-106) gathers these enthronement psalms as the theological response to the Davidic monarchy\'s failure: even when the human king is gone, YHWH remains enthroned. The three-fold royal investiture formula — \"clothed with majesty... clothed with strength... has girded himself\" — is the formal declaration of divine kingship taking up its royal regalia.</p>",
    "2": "<p><b>Your throne has been established from ancient times; you yourself are from everlasting</b> — the antiquity of YHWH\'s enthronement is not recent but pre-cosmic. \"From ancient times\" (<i>me\'az</i>) and \"from everlasting\" (<i>me\'olam</i>) locate the divine throne in the pre-creation order. Unlike human thrones that are established through conquest and can be overthrown, YHWH\'s throne was established before the world existed — it is the precondition of the world, not the world\'s product. This has a direct bearing on the exilic situation: the Babylonian king\'s apparent victory over Jerusalem and its institutions does not displace the eternal divine throne.</p>",
    "3": "<p><b>The great waters have lifted up their voice, LORD; the rushing floods have lifted up their voice and their crashing waves</b> — the personified chaos waters raising their voices against YHWH. In ancient Near Eastern cosmology (particularly the Ugaritic Baal cycle), the primordial waters (Yam, the sea) were the great enemy that the storm god had to defeat before he could be enthroned as king. The Psalter consistently identifies YHWH (not Baal) as the true conqueror of the chaos waters (Ps 29:10; 74:12-14; 89:9-10). The threefold repetition of \"have lifted up\" (<i>nasa\'u</i>) — voice, voice, crashing — imitates the relentless, wave-like nature of the challenge.</p>",
    "4": "<p><b>Mightier than the roar of many waters, mightier than the waves of the sea — the LORD on high is mighty</b> — the answer to v3\'s challenge: YHWH is <i>addiri</i> (mighty, excellent, majestic) beyond the sum of all the waters\' power. The repetition of \"mightier than\" frames the psalm\'s central claim: every power that could challenge divine order is weaker than YHWH. This has eschatological resonance: Revelation uses the voice of many waters as an image of both threatening power (Rev 17:15 — the waters where the Harlot sits are peoples and nations) and divine victory (Rev 14:2; 19:6 — the voice of many waters as the sound of YHWH\'s triumph).</p>",
    "5": "<p><b>Your decrees are completely trustworthy; holiness adorns your house, LORD, forevermore</b> — the transition from cosmic to covenantal. The same YHWH who overcame chaos-waters has also given trustworthy <i>edot</i> (decrees, testimonies — the covenant stipulations). The reliability of divine decrees in history is the moral equivalent of his victory over chaos in creation: the same sovereign power that established the stable world also established a morally ordered covenant. \"Holiness adorns your house\" — the temple as the meeting point of YHWH\'s cosmic kingship and his covenantal presence. The \"forevermore\" (<i>le\'orekh yamim</i>) echoes the eternal enthronement of v2: both throne and house are permanent.</p>"
  },
  "94": {
    "1": "<p><b>O LORD, God who avenges</b> — <i>El neqamot</i> (God of vengeance/retribution) is the specific divine title invoked here. <i>Neqamah</i> is not personal revenge but judicial retribution — the punishment that restores the moral order disrupted by injustice. The same term appears in Deut 32:35 (\"vengeance is mine and retribution\" — quoted in Rom 12:19 and Heb 10:30) and in Isa 34:8 (\"the day of YHWH\'s vengeance\"). The invocation of this specific divine title establishes the psalm\'s framework: this is a judicial lament, appealing to YHWH in his role as the cosmic judge who is obligated by his own character to correct injustice. \"Arise and shine forth\" — the theophany formula calling YHWH to act visibly.</p>",
    "2": "<p><b>Rise up, Judge of the earth</b> — <i>shophet ha-aretz</i> (Judge of the earth) is the title Abraham uses in his intercession for Sodom (Gen 18:25: \"shall not the Judge of all the earth do right?\"). The invocation of YHWH as universal judge — not merely Israel\'s patron deity but the judge of the entire earth — is the theological ground for the complaint that follows: the wicked who oppress the vulnerable are not just violating human norms but are defying the moral order of the cosmic judge. \"Pay back to the proud what they deserve\" (<i>hashev gemul al ge\'im</i>) — the covenant guarantee of proportional retribution (Obad 1:15; Prov 11:31).</p>",
    "3": "<p><b>How long, LORD, will the wicked — how long will the wicked rejoice in triumph?</b> — the doubled \"how long\" is the signature temporal question of the lament psalms (Ps 6:3; 13:1-2; 35:17; 74:10; 79:5; 80:4; 82:2; 89:46). The question is not philosophical (how long philosophically might evil exist?) but practical and covenant-grounded: given that YHWH is the God who avenges (v1) and the Judge of the earth (v2), how long will the current situation persist without his intervention? The double repetition creates the urgency and the felt endlessness of the situation from the psalmist\'s perspective.</p>",
    "4": "<p><b>They spew proud words without end; all who do evil brag without restraint</b> — the specific sin of verbal arrogance: <i>yabbi\'u yedabberu ataq</i> (they pour out/spew arrogant/hard things). <i>Ataq</i> (arrogant, presumptuous) is the word for speech that treats YHWH\'s authority as irrelevant. The imagery of pouring/spewing suggests the uncontrolled overflow of arrogance rather than calculated speech. \"Without restraint\" (<i>yitammeru</i>) — they boast without any internal check or external accountability. The absence of shame is itself a symptom of the practical atheism that v7 makes explicit.</p>",
    "5": "<p><b>They crush your people, LORD, and oppress those who belong to you</b> — the shift from verbal arrogance (v4) to physical oppression. \"Your people\" and \"your inheritance\" (<i>ammekha... nahalatkha</i>) are the covenant terms for Israel as YHWH\'s possession — the ones who belong specifically to him by covenant (Deut 4:20; 9:29). The oppressors are not merely committing social crimes; they are violating YHWH\'s property. This framing makes the divine responsibility explicit: YHWH\'s honor requires that he defend his own people from those who crush them.</p>",
    "6": "<p><b>They murder the widow and the foreigner and kill the fatherless</b> — the three categories of the legally unprotected: the widow (<i>almanah</i>), the foreigner (<i>ger</i>), and the fatherless/orphan (<i>yatom</i>). These three categories appear together repeatedly in Deuteronomy (10:18; 14:29; 16:11; 24:17-21; 26:12-13; 27:19) and the prophets (Isa 1:17, 23; 10:2; Jer 7:6; 22:3; Ezek 22:7; Zech 7:10; Mal 3:5) as the specific persons whom YHWH commands Israel to protect. They have no legal advocate, no family patron, no one to take their case. Murdering them — using violence specifically against those who cannot defend themselves — is the archetype of covenant injustice.</p>",
    "7": "<p><b>And they say, \'The LORD never sees it; the God of Jacob pays no attention\'</b> — the theological rationale for the oppression: practical atheism, the belief that YHWH\'s perception is limited or that he does not concern himself with human affairs. This is exactly the same charge as Ps 64:5 (\"who will see us?\"), Ps 10:11 (\"God has forgotten; he covers his face and never sees\"), and Ezek 8:12 (\"the LORD does not see us; the LORD has forsaken the land\"). The practical atheist is not necessarily a theoretical atheist — they may affirm YHWH\'s existence while denying that his perception and moral governance extends to their specific actions. This belief licenses all manner of oppression.</p>",
    "8": "<p><b>Grasp this, you most senseless among the people — fools, when will you become wise?</b> — the psalm turns from lament to confrontation, addressing the oppressors directly with wisdom vocabulary. <i>Ba\'arim</i> (senseless ones, like animals) and <i>kesilim</i> (fools) — the same pairing as in Ps 92:6. The question \"when will you become wise?\" (<i>matai taskilu</i>) is a rhetorical challenge: wisdom is still available, but the fools are choosing not to acquire it. The wisdom tradition\'s argument is that the practical atheism of v7 is not just morally wrong but epistemically stupid — it makes a claim about YHWH\'s perception that the creation itself refutes.</p>",
    "9": "<p><b>The one who made the ear — does he not hear? The one who formed the eye — does he not see?</b> — the creation-based epistemological argument against practical atheism: the Creator necessarily possesses the capacities he creates. The argument is a fortiori: if human beings (finite creatures) can hear and see, how much more must the Creator of hearing and seeing be able to hear and see? This argument is structurally similar to Paul\'s argument in Rom 1:20 (creation reveals the invisible attributes of God) and appears in various forms in Second Temple wisdom literature. The argument does not prove divine intervention; it proves divine perception — the prerequisite for the just governance the psalmist is requesting.</p>",
    "10": "<p><b>The one who corrects the nations — will he not call them to account? The one who teaches all people</b> — expanding the argument from perception to governance. YHWH who corrects (<i>meyasser</i>, disciplines, chastens) the nations and who teaches (<i>hamelamed</i>) all people has both the knowledge and the governing authority over human affairs. The nations-scope moves beyond Israel: YHWH\'s governance is universal, not merely tribal. The rhetorical questions build to a climax: if YHWH perceives (v9) and governs (v10), then the practical atheism of v7 is both false and self-destructive.</p>",
    "11": "<p><b>The LORD knows what human beings think — that their thoughts are nothing but vapor</b> — the content of YHWH\'s knowledge of human cognition: the <i>machshevot adam</i> (thoughts of humanity) are <i>hevel</i> (vapor, vanity, futility — the keynote word of Ecclesiastes). Paul quotes this verse in 1 Cor 3:20 (\"the Lord knows that the thoughts of the wise are futile\") in the context of warning the Corinthian community against human wisdom that excludes divine wisdom. The divine knowledge of human thought-vanity is both a judgment on practical atheism and a source of comfort to the oppressed: the oppressors\' clever plans for covering their tracks are known to YHWH as vapor.</p>",
    "12": "<p><b>Blessed is the one you discipline, LORD, and instruct from your teaching</b> — the beatitude of divine correction. The one under YHWH\'s <i>yasar</i> (discipline, correction) and <i>lamad</i> (instruction, teaching through Torah) is called blessed (<i>ashre</i>). This is the same paradox as Prov 3:11-12 (\"do not despise the LORD\'s discipline... for the LORD disciplines those he loves, as a father the son he delights in\") and Heb 12:5-11 (which quotes Prov 3:11-12 and applies it to the Christian community under suffering). The discipline that feels like punishment is actually the mechanism of formation: the disciplined one is being made wiser rather than merely punished.</p>",
    "13": "<p><b>Giving him rest in days of trouble until a pit is dug for the wicked</b> — the temporal structure of the blessing. The <i>hashqet</i> (rest, relief, quietness) is given specifically during the days of trouble — not after the trouble ends but within it. This is the same structure as Ps 91:15 (\"I will be with him in his trouble\"). The \"until\" clause places the wicked\'s end as a certainty on the horizon: the pit they are digging for others will become their own grave (compare Ps 7:15; 57:6). The rest the righteous receive is not the absence of trouble but the quality of YHWH\'s presence within it.</p>",
    "14": "<p><b>The LORD will not abandon his people or desert his inheritance</b> — the covenant guarantee stated as a absolute negative. The same covenant faithfulness invoked in Deut 31:6 (Moses\' promise to Joshua: \"he will never leave you nor forsake you\"), 1 Sam 12:22 (\"for his great name\'s sake YHWH will not reject his people\"), and Ps 37:28 (\"the LORD loves the just and will not forsake his faithful ones\"). The double negative construction (<i>lo ya\'azov... velo ya\'azov</i> — not abandon... not desert) is emphatic: the covenant relationship has no provision for divine desertion of the covenant people, regardless of circumstances.</p>",
    "15": "<p><b>Surely justice will return to the righteous, and all who are upright in heart will pursue it</b> — the eschatological confidence that the present moral disorder is not permanent. \"Justice will return\" (<i>ad-tzedek yashov mishpat</i>) — the current situation in which justice is corrupted or absent will be reversed. The \"upright in heart\" (<i>yishrei lev</i>) — those whose inward moral reality matches their outward profession — will actively pursue (<i>ahareyv</i>, follow after) justice when it returns. The verse anticipates a future situation in which righteous governance is restored and the community of the genuinely upright can act on it.</p>",
    "16": "<p><b>Who will stand up for me against the wicked? Who will take my side against evildoers?</b> — the rhetorical question that anticipates the answer: no human advocate is available; only YHWH can serve this role. The social system that should provide legal advocates (family patrons, tribal elders, royal courts) has been captured by the corrupt throne of v20. The psalm\'s appeal is therefore not to human institutions but directly to the divine advocate. This is the same move as Job\'s appeal to a \"redeemer\" (<i>go\'el</i>) who will advocate for him before YHWH (Job 19:25) — when the human legal system fails, the divine one must step in.</p>",
    "17": "<p><b>If the LORD had not been my help, I would very soon have lain in the silence of death</b> — the personal testimony of near-death rescue. \"The silence of death\" (<i>dumah</i>) — the same word as Ps 62:1\'s <i>dumiyyah</i> but here with the specific meaning of the silence of Sheol, the realm of the dead (Ps 115:17: \"the dead do not praise the LORD, nor those who go down to silence\"). The psalmist testifies that without YHWH\'s specific intervention they would now be in Sheol. This testimony is the personal corollary to the theological claim of v14: YHWH does not abandon his people, and the evidence is this specific survival.</p>",
    "18": "<p><b>When I felt my foot giving way, your steadfast love, LORD, held me steady</b> — <i>hesed</i> as the practical force that prevents falling. The foot giving way (<i>motah ragli</i>) is the same stumbling-prevention motif as Ps 91:12 (the angels who hold you up so your foot does not strike against a stone). Here it is <i>hesed</i> itself — covenant loyalty embodied as a steadying force — that prevents the fall. The psalmist did not slip into Sheol (v17) because YHWH\'s hesed actively held them in place. This is the experiential confirmation of the psalm\'s opening theology: the one who has made YHWH their refuge is held steady by covenant love even at the edge of the pit.</p>",
    "19": "<p><b>When anxious thoughts multiply inside me, your comfort brings delight to my soul</b> — the interior psychology of the lament. <i>Sar\'appai</i> (my anxious thoughts, my distracting/conflicted thoughts) multiplying internally is the experience of the mind overwhelmed by threats. The word is rare — appearing also in Ps 139:23 and Job 4:13 — and carries the sense of branching, splitting thoughts that cannot converge on a single response. YHWH\'s <i>tanhumim</i> (consolations, comforts) counter the multiplication of anxiety with delight (<i>shaa\'ashu nafshi</i>, literally: they play with/delight my soul). The divine comforts are not rational arguments but the lived experience of divine nearness.</p>",
    "20": "<p><b>Can a corrupt throne have any fellowship with you — one that enacts harm through its own laws?</b> — the specific indictment of legal injustice: the throne that <i>yotzer amal al-chok</i> (creates trouble/harm by means of statute/law). This is the worst form of wickedness because it uses the apparatus of justice to perpetrate injustice — the law is used as the instrument of oppression. The prophets consistently identify this as the highest form of covenant violation: Isa 10:1-4 (\"woe to those who make unjust laws and issue oppressive decrees\"), Mic 3:9-11 (leaders who despise justice and pervert what is right). The corrupt throne cannot have <i>chevruth</i> (fellowship, association) with YHWH because his character is its direct opposite.</p>",
    "21": "<p><b>They join forces against the lives of the righteous and condemn the innocent to death</b> — the coalition (<i>yagoddu</i>, they band together/conspire) against the legally innocent. The legal system that should protect the innocent is being used to condemn them — the perversion of the judicial process that Proverbs, the prophets, and the Torah consistently identify as the special object of divine wrath. \"Condemn the innocent to death\" (<i>vedam naki yarshi\'u</i>) — declaring the innocent guilty (the legal opposite of justice) produces the death sentence. This is the archetype of the miscarriage of justice that the Psalter and the prophets demand YHWH avenge.</p>",
    "22": "<p><b>But the LORD is my strong fortress, and my God is the rock where I take shelter</b> — the personal confession of faith that answers the corrupt institutions of vv 20-21. The political system has been captured by the corrupt throne; therefore the psalmist cannot appeal to earthly institutions. But YHWH as <i>misgav</i> (fortress, high place) and <i>tsur machsi</i> (rock of my shelter) is the refuge that human corruption cannot compromise. The fortress vocabulary returns from v1\'s invocation and provides the personal counterpart to the theological claim: the God of vengeance (v1) is also the personal fortress (v22).</p>",
    "23": "<p><b>He will pay them back for their sin and destroy them for their evil; the LORD our God will wipe them out</b> — the psalm\'s closing declaration of divine retribution. The three-fold statement of divine judgment — repaying (<i>yashev</i>), destroying (<i>yatzmitem</i>), wiping out (<i>yatzmitem YHWH elohenu</i>) — uses the same covenant vocabulary of complete judgment that appears in the Deuteronomic curses (Deut 28:20-25) and the prophetic oracles against the nations. The final phrase \"YHWH our God\" reclaims the covenant relationship that the corrupt throne denied: the God who judges the wicked is specifically the covenant God of the community that was oppressed.</p>"
  },
  "95": {
    "1": "<p><b>Come, let us sing joyfully to the LORD; let us shout aloud to the Rock who saves us!</b> — the opening imperative <i>lekhu nerannenah</i> (come, let us sing joyfully) is the call to communal worship that opens this and similar enthronement psalms. <i>Hari\'u</i> (shout aloud) is the same battle-cry-as-worship word as Ps 66:1 and 100:1 — the <i>teru\'ah</i> (great shout) that served as both a military battle cry and the prescribed liturgical acclamation of the king\'s presence (Num 23:21; 1 Sam 10:24; 2 Sam 15:10). \"The Rock who saves us\" (<i>tsur yish\'enu</i>) — the geological metaphor for divine protection and stability that runs throughout the Psalter and Deuteronomy (Deut 32:4, 15, 18, 30-31).</p>",
    "2": "<p><b>Let us come before him with thanksgiving and celebrate him with songs of praise</b> — the <i>todah</i> (thanksgiving) approach to the divine presence as the proper mode of entry into covenant worship. The imagery is processional: the community approaches (<i>neqaddemah fanav</i>, come before his face) with <i>todah</i> (thanksgiving offering/song) and <i>zemirot</i> (songs of praise). This processional approach corresponds to the festival pilgrimages to the temple — the three annual feasts when Israel came before YHWH\'s face in Zion (Exod 23:15-17; Deut 16:16). The approach is not casual but structured by the covenant protocol of worship.</p>",
    "3": "<p><b>For the LORD is a great God, a great King greater than all other gods</b> — the \"greater than all other gods\" formula does not necessarily assert that the other gods do not exist; it asserts YHWH\'s supremacy over all rival divine powers. This is the ANE henotheistic formula that the Psalter uses consistently (Ps 96:4; 97:7, 9; 135:5; 136:2). In the context of the Babylonian exile (the implied setting of Book IV), where the apparent defeat of Israel might suggest the defeat of YHWH, the assertion of his supremacy over all divine powers is a polemical claim. Paul uses similar language in 1 Cor 8:5-6 (\"even if there are so-called gods... for us there is but one God, the Father\").</p>",
    "4": "<p><b>The deepest places of the earth are in his hand, and the mountain peaks belong to him</b> — the vertical axis of creation from its deepest recesses to its highest points is entirely under divine sovereignty. The \"depths of the earth\" (<i>mechqere aretz</i>) refers to the subterranean realm — including the foundations of the world and the realm of Sheol (Ps 63:9; 71:20). The mountain peaks (<i>taphot harim</i>) are the highest accessible points in creation. The vertical totality claim is a creation-theology statement: every point in the created order is within YHWH\'s hand, not merely the pleasant middle zone of human habitation.</p>",
    "5": "<p><b>The sea is his — he made it; his own hands shaped the dry land</b> — the sea and dry land are the two great regions distinguished on the third day of creation (Gen 1:9-10). YHWH\'s ownership of the sea is grounded in his making it: the creator has sovereign authority over what he creates. This is an implicit Baal polemic: Baal was the storm god who supposedly controlled the sea and defeated Yam, but Ps 95 asserts that the sea itself belongs to YHWH because he made it. The land shaped by divine hands (<i>yabbashot yadav yatzerahu</i>) is the same language as the pottery-metaphor of human creation (Gen 2:7; Ps 139:13-15) applied to the entire terrestrial surface.</p>",
    "6": "<p><b>Come, let us bow down and worship; let us kneel before the LORD who made us</b> — the three verbs of covenant submission: bowing down (<i>nishtachaveh</i>, prostration — the posture of vassals before a suzerain), worshipping (<i>nikera\'h</i>, bowing/kneeling), and kneeling (<i>nivrekha</i>, bending the knee). The physical postures of the body enact the relational reality of covenant submission. \"Who made us\" (<i>oshenu</i>) — the creation-relationship as the basis for covenant obligation: YHWH\'s authority over us is grounded not only in covenant history but in the prior fact of creation. The one who made the earth (v5) has also made the worshipping community.</p>",
    "7": "<p><b>For he is our God, and we are the people of his pasture, the flock he tends</b> — the shepherd-flock image that runs from the Psalter\'s most personal psalm (Ps 23: \"YHWH is my shepherd\") through the communal confession here to the prophetic vision of Ezek 34 (YHWH as the good shepherd who will rescue his flock from bad shepherds) and to Jesus\' explicit application of Ezek 34 to himself (John 10:11-18). The \"pasture\" (<i>mar\'itu</i>) is the covenantal provision — the land, the guidance, the feeding — that YHWH provides for the community that belongs to him. \"Today — if only you would hear his voice\" — the urgent present tense that pivots the psalm from praise to warning.</p>",
    "8": "<p><b>\'Do not make your hearts stubborn, as at Meribah — as on that day at Massah in the wilderness\'</b> — the historical warning embedded in the call to worship. Meribah (\"quarreling\") and Massah (\"testing\") are the names given to the place where Israel tested YHWH by demanding water in the wilderness (Exod 17:1-7). Two separate incidents are associated with these names: Exod 17 at the beginning of the wilderness wandering and Num 20:2-13 at the end, where Moses himself sinned. Deut 6:16 explicitly commands: \"Do not test YHWH your God as you tested him at Massah.\" The psalm invites the community into worship and immediately confronts them with their ancestors\' failure to trust.</p>",
    "9": "<p><b>\'Your ancestors put me to the test and challenged me, even after seeing all I had done\'</b> — the specification of the wilderness generation\'s sin: testing YHWH <i>despite</i> having seen the evidence. This is the most severe form of unbelief in the Psalter and the Deuteronomic history: not the unbelief of those who have no evidence but the unbelief of those who have overwhelming evidence and choose to act as if they had none. The Exodus generation witnessed the ten plagues, the Reed Sea crossing, the daily manna, and the water from the rock — and still demanded tests of YHWH\'s presence and power. Hebrews 3:7-19 applies this pattern directly to the Christian community as a warning against the same hardness of heart.</p>",
    "10": "<p><b>\'For forty years I was provoked by that generation and declared, \"This people\'s heart keeps wandering; they have never learned my ways\"\'</b> — the forty-year wilderness period as the duration of divine provocation. The fundamental accusation is not specific behavioral failures but a continuous failure of orientation: the heart that \"keeps wandering\" (<i>to\'im lev hem</i>) — the <i>to\'eh</i> (wandering, going astray) is the pastoral image of the sheep that goes its own way rather than following the shepherd (Isa 53:6; Ps 119:176). \"They have never learned my ways\" — not ignorance of the facts of YHWH\'s acts (they had seen everything) but the failure to internalize those facts as a shaping knowledge of who YHWH is and how to live with him.</p>",
    "11": "<p><b>\'So in my anger I swore: \"They will never enter my rest\"\'</b> — the divine oath of exclusion that closes the psalm with the most sobering possible note. The \"rest\" (<i>menuhatiy</i>) is the covenant rest that YHWH had prepared for his people — first the land of Canaan (Deut 3:20; 12:9-10; Josh 21:44) and, in the hermeneutics of Hebrews, the eschatological rest of which the land was a foretaste (Heb 3:7-4:11). Hebrews 3-4 treats Ps 95:11 as the key text for understanding the present urgency of the gospel: if the wilderness generation forfeited the rest through unbelief, the Christian community must heed the same \"today\" (Ps 95:7) before the same oath of exclusion is pronounced over them.</p>"
  },
  "22": {
    "1": "<p>Psalm 22 is the most cited OT Psalm in the NT Passion narratives. Its historical background (David's persecution?) is unknown — the Psalm presents an archetypal experience of abandonment and vindication. The pattern: intense lament (vv. 1-21) → sudden transition to praise (v. 22) → eschatological proclamation (vv. 27-31: 'all the families of the nations shall worship before you ... posterity shall serve him; it shall be told of the Lord to the coming generation'). The Psalm functions in NT usage not as a prediction of specific details but as the divinely-given interpretive framework for understanding the cross: suffering-unto-vindication, abandonment-unto-universal-proclamation.</p>"
  },
  "110": {
    "1": "<p>Psalm 110 is the most frequently quoted OT text in the NT. Jesus cites it in the Synoptics (Matt 22:41-46 and parallels) as a riddle about the Messiah's nature. Peter cites it at Pentecost (Acts 2:34-35). Paul cites it (1 Cor 15:25; Eph 1:20; Col 3:1). Hebrews cites or alludes to it eight times (1:3, 13; 5:6, 10; 6:20; 7:17, 21; 8:1; 10:12-13). Its dominance in NT Christology is due to its dual claim: (1) divine enthronement at God's right hand; (2) eternal Melchizedekian priesthood. These two — divine lordship and perfect priesthood — are the two Christological pillars the NT builds on from this one Psalm.</p>"
  }
}

PSA_CHRIST = {
  "2": {
    "7": "<p>A direct revelation: 'You are my Son; today I have begotten you.' The royal Psalm 2 reaches its Christological fullness in the resurrection. Paul at Pisidian Antioch (Acts 13:33): God raised Jesus, 'as it is written in the second Psalm, You are my Son, today I have begotten you.' The 'today' of divine fatherhood is not the eternal generation alone but the specific day of the resurrection-enthronement, when the Son's identity is publicly declared. Every application of Ps 2:7 in the NT (baptism, transfiguration, resurrection) marks a moment when the Father publicly declares the Son's identity for the community to hear.</p>"
  },
  "22": {
    "1": "<p>A fulfillment: 'My God, my God, why have you forsaken me?' The Passion Psalm that Jesus cited from the cross is both a historical lament (David in extremity) and a Christological prophecy (the Son's abandonment in the atonement). The cry 'why have you forsaken me' is not a failure of faith but a genuine experience of divine absence — the moment when Christ bore the full weight of human sin-under-judgment. The Psalm's movement (dereliction → trust → vindication → universal proclamation) is the death-and-resurrection narrative in miniature. Jesus did not die in despair; the Psalm he cited ends in the world's worship of YHWH through the one who suffered.</p>"
  },
  "110": {
    "1": "<p>A direct revelation: 'The LORD says to my Lord: Sit at my right hand until I make your enemies your footstool.' The most foundational Christological oracle in the OT: the risen and ascended Christ is enthroned at the Father's right hand (the supreme position of divine authority) awaiting the final subjection of all enemies, including death (1 Cor 15:25-26). The present era is the era of Christ's enthronement: he reigns now, his enemies are being progressively placed under his feet, and the ultimate subjection is certain. Ps 110:1 frames the entire NT's understanding of the ascension and the present Christological situation of the cosmos.</p>",

    "4": "<p>A fulfillment: 'You are a priest forever after the order of Melchizedek.' The divine oath of the eternal priesthood is fulfilled in Christ's resurrection, which established him as the priest who never dies. Unlike the Levitical priests who needed to offer sacrifice repeatedly and who were replaced by death, Christ offered himself once and lives forever in the power of an indestructible life (Heb 7:16, 24-25). The Melchizedekian priesthood — prior to Aaron, not from the tribe of Levi, without recorded end — is the OT's own signal that the Levitical system was provisional. Christ's eternal intercession ('he always lives to make intercession for them', Heb 7:25) is the fulfillment of Ps 110:4's oath.</p>"
  }
}

def main():
    e = load_echo('psalms')
    merge_echo(e, PSA_ECHO)
    save_echo('psalms', e)
    print(f'Psalms echo: {len(e)} chapters, {sum(len(v) for v in e.values())} verses')

    c = load_comm('mkt-original', 'psalms')
    merge_comm(c, PSA_ORIGINAL)
    save_comm('mkt-original', 'psalms', c)
    print(f'Psalms original: {len(c)} chapters, {sum(len(v) for v in c.values())} verses')

    c = load_comm('mkt-context', 'psalms')
    merge_comm(c, PSA_CONTEXT)
    save_comm('mkt-context', 'psalms', c)
    print(f'Psalms context: {len(c)} chapters, {sum(len(v) for v in c.values())} verses')

    c = load_comm('mkt-christ', 'psalms')
    merge_comm(c, PSA_CHRIST)
    save_comm('mkt-christ', 'psalms', c)
    print(f'Psalms christ: {len(c)} chapters, {sum(len(v) for v in c.values())} verses')

if __name__ == '__main__':
    main()
